import { Strength, Weakness } from '../../types/evaluation';
import { ConversationMemory } from '../../types/conversationMemory';

export const updateStrengthsAndWeaknesses = (
  currentStrengths: Strength[],
  currentWeaknesses: Weakness[],
  memory: ConversationMemory,
  questionNumber: number,
  baseScore: number,
  extractedSkills: string[],
  extractedWeaknesses: string[]
): { strengths: Strength[], weaknesses: Weakness[] } => {
  const strengths = [...currentStrengths];
  const weaknesses = [...currentWeaknesses];

  // 1. Process explicit weaknesses generated by FollowUp engine
  for (const weakTopic of extractedWeaknesses) {
    if (!weaknesses.find(w => w.topic.toLowerCase() === weakTopic.toLowerCase())) {
      weaknesses.push({
        topic: weakTopic,
        evidence: `Candidate struggled with this concept during Question ${questionNumber}.`,
        questionNumber,
        recommendation: `Review fundamental concepts related to ${weakTopic}.`
      });
    }
  }

  // 2. Process explicit strengths / skills
  if (baseScore >= 80) {
    for (const skill of extractedSkills) {
      if (!strengths.find(s => s.topic.toLowerCase() === skill.toLowerCase())) {
        strengths.push({
          topic: skill,
          evidence: `Demonstrated strong knowledge of ${skill} in Question ${questionNumber}.`,
          questionNumber,
          confidence: baseScore
        });
      }
    }
  }

  // 3. Process structural heuristics based on score
  if (baseScore <= 40) {
    const topic = memory.topicsCovered.length > 0 ? memory.topicsCovered[memory.topicsCovered.length - 1] : 'General Technical';
    if (!weaknesses.find(w => w.topic === topic)) {
      weaknesses.push({
        topic,
        evidence: `Provided an incomplete or incorrect answer for ${topic}.`,
        questionNumber,
        recommendation: `Focus on deeper understanding of ${topic} instead of surface-level knowledge.`
      });
    }
  }

  // Deduplicate and cap sizes (e.g., keep top 10 most relevant)
  // For now, we just return the full arrays
  return { strengths, weaknesses };
};
